// Tenacity 5.1 - Disabler.java (Watchdog C0F+C00 queue)
// Reproduced from actual 1.8.9 client source
if (!timer.hasTimeElapsed(350)) {
  if (event.getPacket() instanceof C0FPacketConfirmTransaction
    || event.getPacket() instanceof C00PacketKeepAlive) {
    event.cancel();
    watchdogC0FC00Packets.add(event.getPacket());
  }
} else if (!watchdogC0FC00Packets.isEmpty()) {
  watchdogC0FC00Packets.forEach(PacketUtils::sendPacketNoEvent);
  watchdogC0FC00Packets.clear();
}

// Lycoris 2.0 - DisablerMod.java (MAX_VALUE spoof)
if (event.getPacket() instanceof C0FPacketConfirmTransaction) {
  C0FPacketConfirmTransaction p =
    (C0FPacketConfirmTransaction) event.getPacket();
  mc.getNetHandler().addToSendQueueSilent(
    new C0FPacketConfirmTransaction(Integer.MAX_VALUE,
      p.getUid(), false));
  event.setCancelled();
}

// Tenacity 5.1 - Velocity (C0F Cancel mode)
if (event.getPacket() instanceof C0FPacketConfirmTransaction && mc.thePlayer.hurtTime > 0) {
  event.cancel();
}

// November 0.2 - PingSpoof
if (p instanceof C0FPacketConfirmTransaction || p instanceof C00PacketKeepAlive) {
  this.packets.add((int)(System.currentTimeMillis() + this.ping.getValue()), p);
  e.setCancelled(true);
}
